### Implement Session Update Logic in Supabase Proxy Handler

Source: https://github.com/supabase/supabase/blob/master/apps/docs/content/guides/auth/server-side/creating-a-client.mdx

Implements the updateSession function that refreshes Auth tokens by calling supabase.auth.getClaims(), updates request cookies for Server Components, and sets response cookies for the browser. This ensures the Auth token is always current across server and client.

```typescript
import { type NextRequest, NextResponse } from 'next/server'
import { createServerClient, CookieOptions } from '@supabase/ssr'

export async function updateSession(request: NextRequest) {
  let supabaseResponse = NextResponse.next({
    request
  })

  const supabase = createServerClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
    {
      cookies: {
        getAll() {
          return request.cookies.getAll()
        },
        setAll(cookiesToSet) {
          cookiesToSet.forEach(({ name, value, options }) =>
            supabaseResponse.cookies.set(name, value, options)
          )
        }
      }
    }
  )

  // This refreshes a user's auth token
  await supabase.auth.getUser()

  return supabaseResponse
}
```

